func TestLoadPolicyPack_Security(t *testing.T) {
	pack, err := config.LoadPolicyPack(policiesPath("security.yml"))
	if err != nil {
		t.Fatalf("LoadPolicyPack(security.yml) error: %v", err)
	}

	if pack.Name != "security" {
		t.Errorf("Name = %q, want security", pack.Name)
	}
	// IsGlobal() only checks language — security pack has no language, so it's global
	if !pack.IsGlobal() {
		t.Error("security pack with empty language should be global")
	}
	if pack.Language != "" {
		t.Errorf("Language should be empty, got %q", pack.Language)
	}
	if len(pack.PathPatterns) != 3 {
		t.Errorf("PathPatterns = %d, want 3", len(pack.PathPatterns))
	}
	if len(pack.Rules) != 2 {
		t.Errorf("len(Rules) = %d, want 2", len(pack.Rules))
	}

	// Verify critical severity
	if pack.Rules[0].Severity != domain.SeverityCritical {
		t.Errorf("rule[0].Severity = %v, want critical", pack.Rules[0].Severity)
	}
}

func TestLoadPolicyPacks_Dir(t *testing.T) {
	dir := filepath.Join("..", "..", "testdata", "policies")
	packs, err := config.LoadPolicyPacks(dir)
	if err != nil {
		t.Fatalf("LoadPolicyPacks() error: %v", err)
	}

	if len(packs) != 7 {
		t.Fatalf("len(packs) = %d, want 7", len(packs))
	}

	// Should find all packs
	names := make(map[string]bool)
	for _, p := range packs {
		names[p.Name] = true
	}
	for _, expected := range []string{"go-standard", "go-library", "python-standard", "rust-standard", "security", "swift-standard", "ts-standard"} {
		if !names[expected] {
			t.Errorf("missing %s pack", expected)
		}
	}
}

func TestLoadPolicyPack_GoLibrary(t *testing.T) {
	pack, err := config.LoadPolicyPack(policiesPath("go-library.yml"))
	if err != nil {
		t.Fatalf("LoadPolicyPack(go-library.yml) error: %v", err)
	}

	if pack.Name != "go-library" {
		t.Errorf("Name = %q, want go-library", pack.Name)
	}
	if pack.Language != "go" {
		t.Errorf("Language = %q, want go", pack.Language)
	}
	if len(pack.PathPatterns) != 1 || pack.PathPatterns[0] != "internal/**" {
		t.Errorf("PathPatterns = %v, want [internal/**]", pack.PathPatterns)
	}
	if len(pack.Rules) != 2 {
		t.Fatalf("len(Rules) = %d, want 2", len(pack.Rules))
	}

	// Verify rules are no-panic and no-os-exit
	ids := map[string]bool{}
	for _, r := range pack.Rules {
		ids[r.ID] = true
	}
	if !ids["no-panic"] {
		t.Error("missing no-panic rule")
	}
	if !ids["no-os-exit"] {
		t.Error("missing no-os-exit rule")
	}
}

